import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface TopPick {
  title: string;
  rating: number;
  genre: string;
  runtime: number;
}

interface MovieData {
  topPicks: TopPick[];
}

export default function Widget() {
  const movieData = response.data as MovieData;
  const { topPicks } = movieData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#222222' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
            Movie Buzz Top Picks
          </Typography>
          {topPicks.map((pick, index) => (
            <Box key={index} sx={{ bgcolor: '#333333', borderRadius: 2, p: 1.5 }}>
              <Typography variant="body1" sx={{ color: '#FFC107', fontWeight: 500 }}>
                {pick.title}
              </Typography>
              <Stack direction="row" spacing={0.5} alignItems="center" sx={{ mt: 0.5 }}>
                <Chip label={`${pick.genre}`} sx={{ fontSize: '11px', bgcolor: '#444444', color: '#FFC107' }} />
                <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                  {pick.runtime} min
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                  Rating: {pick.rating.toFixed(1)}
                </Typography>
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
